import{u as h,_ as a}from"./BaseSection-H-6wW8Bc.js";import{h as n}from"./siteContent-bxfCP6VW.js";import{_ as g}from"./RichText-BCD_A6C_.js";import{_ as m}from"./HeroSection-BeFjoAJX.js";import{H as c}from"./HomeImageTextBlock-OhYfAWFd.js";import{N as b}from"./NextExpert-T290qzBy.js";import{_ as f,o as t,c as u,a as r,u as e,w as d,F as k,r as p,b as i,t as o,d as w,m as z}from"./index-DxcjFBwH.js";import"./BaseButton-ABmlCZo_.js";const V=[{id:1,imageUrl:"/images/homeblocks/herbsttagung25.webp",imageAlt:"Versammlungsfoto der Mitglieder zu Herbsttagung 2025",imagePosition:"left",heading:"Rückblick auf die Herbsttagung 2025 in Dietzenbach",body:`Die diesjährige Herbsttagung des Low Vision Kreises fand am **14. und 15. November 2025 im Hotel Sonnenhof in Dietzenbach** statt. Wieder blicken wir auf zwei erfolgreiche Tage zurück, geprägt von einem freundschaftlichen Miteinander, intensiven Gesprächen und vielen fachlichen Impulsen.

 **Der Freitag startete mit der offiziellen Begrüßung durch den Vorstand**, bevor die Referenten mit einer breiten Themenvielfalt in das Programm einstiegen. Von digitalen Sehhilfen als moderne Alltagsbegleiter – „Die Welt durch andere Augen“ – über Kommunikationsstrategien und Telemedizin bis hin zu neuen Erkenntnissen zu CVI und modernen Pol-Gläsern war für alle Praxisbereiche etwas dabei. 

 Auch am **Samstag wurde das Publikum fachlich weitergeführt.** Beiträge aus Sehschule, Therapie und Patientenführung standen ebenso im Mittelpunkt wie ein Blick darauf, welche persönlichen Möglichkeiten Patienten nach schwerwiegenden Diagnosen noch haben. Parallel dazu präsentierten zahlreiche Aussteller – u. a. aus den Bereichen digitale Hilfsmittel, Brillentechnik und Systemlösungen – ihre aktuellen Entwicklungen und Produktneuheiten. 

 Wie immer blieb auch Raum für Austausch, Diskussionen und persönliche Gespräche. Das angenehme, familiäre Klima, das Fachwissen der Teilnehmenden und die lebendigen Gespräche haben die Tage erneut zu einer wertvollen Erfahrung gemacht.Wir danken allen Referenten, Ausstellern und Teilnehmern für ihren Beitrag zu einer rundum gelungenen Tagung und freuen uns bereits auf das nächste Wiedersehen.`},{id:2,imageUrl:"/images/homeblocks/fruhjahrstagung.webp",imageAlt:"Versammlungsfoto der Mitglieder zu Frühjahrstagung 2025",imagePosition:"right",heading:"Eine gelungene Frühjahrstagung 2025 mit Jubiläumsstimmung",body:`Am 28. und 29. März 2025 fand unsere diesjährige Frühjahrstagung in der geschichtsträchtigen Stadt Potsdam statt – und es war ein voller Erfolg! Neben spannenden Vorträgen, intensiven Fachdiskussionen und interessanten Produktpräsentationen stand in diesem Jahr ein ganz besonderes Ereignis im Mittelpunkt: **20 Jahre Low-Vision-Kreis!** 

 Die Veranstaltung begann mit einer herzlichen Begrüßung durch den Vorstand, gefolgt von einem vielseitigen und hochkarätig besetzten Vortragsprogramm. Besonders hervorzuheben sind die Beiträge von Prof. Dr. Liekfeld, Fr. Esther Goeltzer zu den Themen Sehen im Alter sowie binokulare Probleme nach Augenoperationen, außerdem Prof. Dr. Bernhard Sabel, der uns spannende Einblicke in das Thema Low Vision Erholung durch Neuromodulation gewährte.

 Ein besonderes Highlight war der Jubiläumsabend im Restaurant „Zum Fliegenden Holländer“, bei dem in geselliger Runde auf zwei erfolgreiche Jahrzehnte zurückgeblickt wurde. Die vorherige Stadtführung am Abend rundete das Programm kulturell ab und bot Zeit für persönlichen Austausch in entspannter Atmosphäre.

 Ein herzliches Dankeschön geht an alle Referentinnen und Referenten, unsere Aussteller sowie die vielen engagierten Mitglieder, die diese Veranstaltung erneut zu einem besonderen Erlebnis gemacht haben.

 Wir freuen uns schon auf die nächste Tagung im Herbst – und auf weitere gemeinsame Jahre im Zeichen des besseren Sehens!`},{id:3,imageUrl:"/images/homeblocks/herbsttagung24.webp",imageAlt:"Versammlungsfoto der Mitglieder zu Herbsttagung 2024",imagePosition:"left",heading:"Herbsttagung in Dietzenbach",body:`Am 15. und 16. November 2024 fand unsere Herbsttagung im Hotel Sonnenhof in Dietzenbach statt. Zahlreiche Mitglieder und Interessierte unseres Vereins nahmen an der Veranstaltung teil, die durch eine Vielfalt an Fachvorträgen und Präsentationen geprägt war.

 Der erste Tag begann mit einer herzlichen Begrüßung durch den Vorstand. Im Anschluss folgten spannende Vorträge, unter anderem von H. Streitt (Eschenbach), der über blendfreies Sehen referierte, und H. Förster (Schweizer), der innovative Beleuchtungslösungen präsentierte. Besondere Aufmerksamkeit erregten auch Vorträge zur Anwendung künstlicher Intelligenz, wie die Envision Glasses Pro, sowie das barrierefreie digitale Leitsystem von H. Wilke (Mind Tags Group). Ein besonderes Highlight war der Vortrag von Frau Dr. Hochheimer, die die Bedeutung der genetischen Diagnostik bei Augenerkrankungen erläuterte. Sie zeigte auf, wie genetische Analysen nicht nur zur Ursachenforschung, sondern auch zur Therapieentwicklung beitragen können.

 Am zweiten Tag standen Vorträge zu Themen wie taktilen Grafikdisplays und modernen Hilfsmitteln für sehbehinderte Menschen im Fokus. Dabei wurden technische Neuerungen anschaulich demonstriert und den Teilnehmern Möglichkeiten geboten, diese vor Ort auszuprobieren.

 Neben dem fachlichen Austausch blieb ausreichend Zeit für Networking und den persönlichen Kontakt mit Ausstellern und anderen Teilnehmern.

 Die Tagung war ein voller Erfolg und zeigte einmal mehr die Bedeutung unseres Engagements für Menschen mit Sehbeeinträchtigungen. Wir freuen uns bereits auf die nächste Veranstaltung im Frühjahr 2025!`},{id:4,imageUrl:"/images/homeblocks/vorstand.webp",imageAlt:"Neuer Vorstand und neue Beisitzer des Vorstands",imagePosition:"right",heading:"Neuer Vorstand und neue Beisitzer des Vorstands",body:`Wir freuen uns sehr, den neuen Vorstand und Beisitzer vorstellen zu dürfen. Bei den Wahlen wurden als erste Vorsitzende Fr. Susanne Fischer sowie als zweite Vorsitzende Fr. Sandra Endler gewählt.Auch wurden die Beisitzer ausgetauscht sowie bestätigt.

 Wir freuen uns auf die neue Zusammensetzung und die gemeinsame Vereinsarbeit.`}],T={class:"container"},v={class:"section-intro__label"},_={class:"mission-headline"},A={__name:"HomeView",setup(B){return h({title:"Low Vision Kreis",description:"Low Vision Kreis – Spezialisierte Beratung und Hilfsmittel für Menschen mit Sehbehinderung. Finden Sie zertifizierte Experten in Ihrer Nähe."}),(H,S)=>(t(),u("div",null,[r(m,{tagline:e(n).hero.tagline,headline:e(n).hero.headline,body:e(n).hero.body,ctaText:e(n).hero.ctaText,ctaTo:e(n).hero.ctaTo,secondaryText:e(n).hero.secondaryCtaText,secondaryTo:e(n).hero.secondaryCtaTo,backgroundImage:e(n).hero.backgroundImage},null,8,["tagline","headline","body","ctaText","ctaTo","secondaryText","secondaryTo","backgroundImage"]),r(a,{variant:"alt"},{default:d(()=>[i("div",T,[i("div",null,[i("span",v,o(e(n).missionTeaser.label),1),i("h2",_,o(e(n).missionTeaser.headline),1),r(g,{content:e(n).missionTeaser.body,class:"lead"},null,8,["content"])])])]),_:1}),r(b),(t(!0),u(k,null,p(e(V),(s,l)=>(t(),w(a,{key:s.id,variant:l%2===0?"default":"alt"},{default:d(()=>[r(c,z({ref_for:!0},s),null,16)]),_:2},1032,["variant"]))),128))]))}},I=f(A,[["__scopeId","data-v-925d7feb"]]);export{I as default};
